var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"이지스 8 PBLIT 보안 절차 적용\\n열람 승인 대상:A017 / CP002\\nCCN No. VCDF003A14437-04: Cindy Luper","JPN":"イージス8 PBLIT保安手続き適用\\n閲覧承認対象:A017 / CP002\\nCCN No. VCDF003A14437-04: Cindy Luper","ENG":"Aegis 8 PBLIT Security Protocol Applied\\nAccess Approval Subject: A017 / CP002\\nCCN No. VCDF003A14437-04: Cindy Luper","TWN":"(TWN)이지스 8 PBLIT 보안 절차 적용\\n열람 승인 대상:A017 / CP002\\nCCN No. VCDF003A14437-04: Cindy Luper"},"stage":{"bg":"BLACK","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"언제 해도 번거롭네요, 보안 절차란.","JPN":"いつしても煩わしいですね、保安手続きとは。","ENG":"Security protocols are always such a hassle, no matter when you go through them.","TWN":"(TWN)언제 해도 번거롭네요, 보안 절차란."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"불편해 말게. 노리는 녀석들이 어지간히 많아야지. 인기 있다는 것도 괴롭군.","JPN":"不便で巻きなさい。狙う野郎どもがよほど多いと思わなければならない。人気あるということもつらいね。","ENG":"Don't complain about the inconvenience. It means plenty of people are targeting us. Being popular is a pain.","TWN":"(TWN)불편해 말게. 노리는 녀석들이 어지간히 많아야지. 인기 있다는 것도 괴롭군."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"그래, 이번엔 어쩐 일인가. 자금? 인력?","JPN":"そう、今回はどうする事か。資金?人力?","ENG":"So, what's the matter this time? Funding? Personnel?","TWN":"(TWN)그래, 이번엔 어쩐 일인가. 자금? 인력?"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"당일 갱신된 카운터를 보고 드리러 왔습니다. ","JPN":"当日更新されたカウンターをご報告申し上げに来ました。","ENG":"I've come to report on a Counter who was updated today.","TWN":"(TWN)당일 갱신된 카운터를 보고 드리러 왔습니다. "},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"신디 루퍼, 16세. 현재 성황청 신앙교리성 부설 3과 소속 카운터입니다.  ","JPN":"シンディ・ルーパー、16歳。現在ソン黄清信仰教理性敷設3と所属カウンターです。","ENG":"Cindy Luper, 16 years old. Currently a Counter affiliated with Section 3 of the Holy See's Faith and Doctrine Bureau.","TWN":"(TWN)신디 루퍼, 16세. 현재 성황청 신앙교리성 부설 3과 소속 카운터입니다.  "},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"부설 3과?","JPN":"敷設3科?","ENG":"Section 3?","TWN":"(TWN)부설 3과?"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"문제 있으신가요.","JPN":"問題あるのでしょうか。","ENG":"Is there a problem?","TWN":"(TWN)문제 있으신가요."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"있다 마다. 이단이라면 같이 싸우던 동료들도 냉큼 화형해 버릴 족속들이지.","JPN":"ある麻だ。異端なら一緒に戦った同僚もすぐに火刑してしまう族属だ。","ENG":"Every single time. They're the type who'd burn their own comrades at the stake without hesitation if they deemed them heretics.","TWN":"(TWN)있다 마다. 이단이라면 같이 싸우던 동료들도 냉큼 화형해 버릴 족속들이지."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"주님의 미친개들. 이면세계가 사라지면 저것들부터 지옥으로 쫓겨날 걸세.","JPN":"神様の及んだ犬。カウンターサイドが消えればあれから地獄で追い出されるはずであるよ。","ENG":"The Lord's mad dogs. If the Otherworld disappeared, they'd be the first ones chased into hell.","TWN":"(TWN)주님의 미친개들. 이면세계가 사라지면 저것들부터 지옥으로 쫓겨날 걸세."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"신디 쿠퍼는 출신 성분이 다릅니다. 일요일에 늦잠 잤다고 화형시키진 않겠죠.","JPN":"シンディクポは出身成分が違います。日曜日に寝坊したと火刑させないだろう。","ENG":"Cindy Luper's background is different. They won't burn her at the stake for sleeping in on Sundays.","TWN":"(TWN)신디 쿠퍼는 출신 성분이 다릅니다. 일요일에 늦잠 잤다고 화형시키진 않겠죠."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"불행 중 다행이군.","JPN":"不幸中の幸いだね。","ENG":"A stroke of luck amidst misfortune, then.","TWN":"(TWN)불행 중 다행이군."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"......그래서, 16세라.","JPN":"......それで、16セーラ。","ENG":"......So, she's sixteen.","TWN":"(TWN)......그래서, 16세라."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"\\n카운터라도 서원은 해야 들어갈 수 있을 텐데. 3과도 인력난이란 건가.","JPN":"\\nカウンターでも書院は年だけは入ることができるつもりだったのですが。3とも人手不足という濃いか。","ENG":"\\nEven as a Counter, she'd need to take vows to get in. Is Section 3 that short on manpower?","TWN":"(TWN)\\n카운터라도 서원은 해야 들어갈 수 있을 텐데. 3과도 인력난이란 건가."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"물론, 말씀대로 관리 실패 이후 그쪽도 일이 부쩍 늘어났죠.","JPN":"もちろん、お話どおり管理失敗以後そちらも事がかなり増えたんです。","ENG":"Of course, as you mentioned, their workload has increased significantly since the management failure.","TWN":"(TWN)물론, 말씀대로 관리 실패 이후 그쪽도 일이 부쩍 늘어났죠."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"관계자를 통해 입수한 정보에 따르면, 내부 문제도 여러 차례 일어났다고 합니다.","JPN":"関係者を通じて手に入れた情報によれば、内部問題も何回も起きたと言います。","ENG":"According to information obtained through contacts, there have been several internal issues as well.","TWN":"(TWN)관계자를 통해 입수한 정보에 따르면, 내부 문제도 여러 차례 일어났다고 합니다."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"신뢰할 수 있는 라인인가?","JPN":"信頼することができるラインであるか?","ENG":"Is this a reliable source?","TWN":"(TWN)신뢰할 수 있는 라인인가?"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"안심하셔도 좋습니다. 신뢰할 수 있는 방법으로 얻은 정보니까요.","JPN":"安心しても良いです。信頼することができる方法で得た情報だから。","ENG":"You can rest assured. It's information obtained through reliable means.","TWN":"(TWN)안심하셔도 좋습니다. 신뢰할 수 있는 방법으로 얻은 정보니까요."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"...자세히는 듣지 않겠네.","JPN":"...詳細にはきかないね。","ENG":"...I'd rather not hear the details.","TWN":"(TWN)...자세히는 듣지 않겠네."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"\\n다 큰 어른이 무서워서 밤에 화장실도 못 가면 쓰나.","JPN":"\\nすべて大きい大人が恐ろしくて夜にトイレも行くことができなければ使うか。","ENG":"\\nWhat good is a grown adult who can't even go to the bathroom at night because they're scared?","TWN":"(TWN)\\n다 큰 어른이 무서워서 밤에 화장실도 못 가면 쓰나."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"농담이 과하시군요.","JPN":"冗談が過夏柴ですね。","ENG":"That's a bit much for a joke, sir.","TWN":"(TWN)농담이 과하시군요."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"본론으로 돌아가죠. 신디 루퍼는 10개월 전부터 부설 3과에서 활동 중입니다. ","JPN":"本論に帰ってくれ。シンディ・ルーパーは10ヶ月前から敷設3科で活動中です。","ENG":"Let's return to the main subject. Cindy Luper has been active in Section 3 for 10 months.","TWN":"(TWN)본론으로 돌아가죠. 신디 루퍼는 10개월 전부터 부설 3과에서 활동 중입니다. "},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"실적으로는 역대 부설 3과 인원 중 다섯 손가락에 꼽힐 만합니다만...","JPN":"実績には歴代敷設3と人員中五本指に数えられるに値しますが...","ENG":"Performance-wise, she's among the top five in Section 3 history, but...","TWN":"(TWN)실적으로는 역대 부설 3과 인원 중 다섯 손가락에 꼽힐 만합니다만..."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"버르장머리가 없고 자신감이 과한 데다, 비상식적인 전투 방식 때문에 부설 3과에서도 잡음이 많습니다. ","JPN":"ボルジャングモリがなくて自信感が科したうえに、非常識的な戦闘方式のために敷設3科でも雑音が多いです。","ENG":"She lacks discipline, has excessive confidence, and her nonsensical combat style causes considerable controversy even within Section 3.","TWN":"(TWN)버르장머리가 없고 자신감이 과한 데다, 비상식적인 전투 방식 때문에 부설 3과에서도 잡음이 많습니다. "},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"들으면 들을수록 누구 얼굴이 눈에 아른거리는데, 기분 탓이겠지?","JPN":"きけばきくほど誰顔が目にちらちらするのに、気のせいである?","ENG":"The more I hear, the more someone's face comes to mind... must be my imagination?","TWN":"(TWN)들으면 들을수록 누구 얼굴이 눈에 아른거리는데, 기분 탓이겠지?"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"기분 탓이겠죠.","JPN":"気のせいでしょう。","ENG":"It must be your imagination.","TWN":"(TWN)기분 탓이겠죠."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"흠. 그러길 바라네. 그런 아가씨는 세상에 한 명으로도 과해.","JPN":"傷。そうしてほしいね。そんなお嬢さんは世の中に一人でもあんまりである。","ENG":"Hmph. I hope so. One such young lady in this world is more than enough.","TWN":"(TWN)흠. 그러길 바라네. 그런 아가씨는 세상에 한 명으로도 과해."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}}]`);export{e as default};